mapper.select:
SELECT id, session_id, user_id, role, content, answer_mode, citations_json, sources_json, variants_json, created_at, feedback_helpful, feedback_note, feedback_at
FROM rag_chat_messages
WHERE user_id = #{userId}
  AND session_id = #{sessionId}
ORDER BY id ASC

mapper.sql:
role = 'assistant'
AND feedback_helpful IS NOT NULL

