        LOWER(COALESCE(feedback_note, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(COALESCE(content, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(COALESCE(session_id, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
