mapper.update:
UPDATE rag_chat_messages
SET feedback_helpful = #{helpful},
    feedback_note = #{note},
    feedback_at = CURRENT_TIMESTAMP
WHERE user_id = #{userId}
  AND session_id = #{sessionId}
  AND id = #{messageId}

UPDATE rag_chat_messages
SET variants_json = #{variantsJson}
WHERE user_id = #{userId}
  AND session_id = #{sessionId}
  AND id = #{messageId}

